query:
-- Detalhe unitPendingQueue com tenantId=1
SELECT upq.id, upq.tenantId, upq.productCode, upq.xmlUnit, upq.reason, upq.status, upq.createdAt
FROM unitPendingQueue upq
WHERE upq.tenantId = 1
ORDER BY upq.createdAt DESC;

-- Distribuição de tenantId em unitAliases
SELECT 'unitAliases' AS tabela, tenantId, COUNT(*) AS qtd FROM unitAliases GROUP BY tenantId ORDER BY tenantId;

-- Distribuição de tenantId em productConversions
SELECT 'productConversions' AS tabela, tenantId, COUNT(*) AS qtd FROM productConversions GROUP BY tenantId ORDER BY tenantId;

-- Distribuição de tenantId em labelAssociations
SELECT 'labelAssociations' AS tabela, tenantId, COUNT(*) AS qtd FROM labelAssociations GROUP BY tenantId ORDER BY tenantId;

